local G = DYCInfoPanel local require = G.DYCModRequire local odwutil = require( "dyc_odwutil" ) local ShowObjectDetail = odwutil.ShowObjectDetail local lastItem = nil local function UpdateCursorText(self, ...) if TheInput:ControllerAttached() then local activetile = self.active_slot and self.active_slot.tile local cursortile = self.cursortile local inv_item = activetile and activetile.item local active_item = cursortile and cursortile.item local tile = cursortile or activetile local item = active_item or inv_item if item ~= lastItem then ShowObjectDetail(item, tile) lastItem = item end end return self.dycOldUpdateCursorText(self, ...) end local function DYCInvBar(self) self.dycOldUpdateCursorText = self.UpdateCursorText self.UpdateCursorText = UpdateCursorText end return DYCInvBar 